const apps = $input.all();
const results = [];

for (const app of apps) {
    const a = app.json;
    const track = a.pipeline_track;
    const state = a.current_state;
    const daysInState = parseFloat(a.days_in_state) || 0;
    const followUps = a.follow_up_count || 0;

    const thresholds = {
        corporate: {
            applied: { warn: 7, ghost: 14, maxFollowups: 2 },
            acknowledged: { warn: 10, ghost: 21, maxFollowups: 1 },
            screening: { warn: 7, ghost: 14, maxFollowups: 1 },
            interviewing: { warn: 7, ghost: 14, maxFollowups: 1 },
        },
        academic: {
            applied: { warn: 21, ghost: 56, maxFollowups: 1 },
            acknowledged: { warn: 28, ghost: 56, maxFollowups: 1 },
            academic_longlisted: { warn: 28, ghost: 56, maxFollowups: 1 },
            academic_shortlisted: { warn: 21, ghost: 42, maxFollowups: 1 },
            screening: { warn: 14, ghost: 28, maxFollowups: 1 },
            interviewing: { warn: 21, ghost: 42, maxFollowups: 1 },
        }
    };

    const t = ((thresholds[track] || thresholds.corporate)[state]);
    if (!t) {
        results.push({ json: { ...a, action: 'ok' } });
        continue;
    }

    let action = 'ok';
    if (daysInState >= t.ghost && followUps >= t.maxFollowups) {
        action = 'ghosted';
    } else if (daysInState >= t.warn && followUps < t.maxFollowups) {
        action = 'follow_up_due';
    }

    const reminderType = followUps === 0 ? 'initial_follow_up' : 'second_follow_up';

    results.push({ json: { ...a, action, thresholdDays: t.warn, ghostDays: t.ghost, reminderType, daysInState: Math.round(daysInState) } });
}

return results;

const a = $input.first().json;
const company = a.company_name;
const title = a.job_title;
const days = a.daysInState;
const track = a.pipeline_track;
const state = a.current_state;
const ref = a.reference_number ? ` (Ref: ${a.reference_number})` : '';

let suggestedAction = '';
let template = '';

if (track === 'academic') {
    suggestedAction = `Check university HR portal for status update. Academic hiring timelines are longer — ${days} days is approaching the follow-up threshold.`;
    template = `Dear Hiring Committee,\n\nI submitted my application for the ${title} position${ref} and wanted to confirm it was received. I remain very interested in this opportunity and would welcome any update on the timeline.\n\nKind regards,\nSelvi`;
} else {
    suggestedAction = `Send a polite follow-up email to ${company}. You applied ${days} days ago with no response.`;
    template = `Dear Hiring Manager,\n\nI applied for the ${title} role${ref} at ${company} and wanted to follow up. I'm very interested in this opportunity and would appreciate any update on the status of my application.\n\nBest regards,\nSelvi`;
}

const subject = `Follow-up needed: ${title} at ${company} (${days} days)`;
const bodyHtml = `<h3>Follow-Up Reminder</h3><p><strong>${title}</strong> at <strong>${company}</strong></p><p>You applied ${days} days ago (${track} track, state: ${state}).</p><p><strong>Suggested action:</strong> ${suggestedAction}</p><h4>Suggested follow-up email:</h4><pre>${template}</pre>`;

return [{ json: { ...a, subject, bodyHtml, suggestedAction, template } }];

const items = $input.all();
const results = [];
for (const item of items) {
    const a = item.json;
    if (!a.id) continue;
    const hours = Math.round(parseFloat(a.hours_until_deadline) || 0);
    results.push({ json: {
        ...a,
        hours_remaining: hours,
        subject: `DEADLINE: ${a.job_title} at ${a.company_name} expires in ${hours} hours`,
        bodyHtml: `<h3>Application Deadline Approaching</h3><p><strong>${a.job_title}</strong> at <strong>${a.company_name}</strong></p><p>Deadline in <strong>${hours} hours</strong>.</p><p>Current status: ${a.current_state}. Apply now or mark as expired.</p>`
    }});
}
return results.length > 0 ? results : [{ json: { skip: true } }];
